import { IUiPath } from '../core/index';

/**
 * Insights Types
 * Shared types for Maestro insights analytics endpoints
 */
/**
 * Optional filters for Insights "top" endpoint queries.
 * All fields are optional — pass any combination to narrow results.
 */
interface TopQueryOptions {
    /** Filter by package identifier */
    packageId?: string;
    /** Filter by process key */
    processKey?: string;
    /** Filter by package version */
    version?: string;
}
/**
 * Common fields returned by all Insights "top" endpoints
 */
interface GetTopBaseResponse {
    /** The package identifier */
    packageId: string;
    /** The unique process key */
    processKey: string;
}
/**
 * Response for the top run count Insights endpoint
 */
interface GetTopRunCountResponse extends GetTopBaseResponse {
    /** Number of times the process was run in the given time range */
    runCount: number;
}
/**
 * Response for the top failure count Insights endpoint
 */
interface GetTopFaultedCountResponse extends GetTopBaseResponse {
    /** Number of faulted instances in the given time range */
    faultedCount: number;
}
/**
 * SDK response for top elements with failure.
 * Shared by both MaestroProcesses and Cases — no service-specific enrichment.
 */
interface ElementGetTopFailedCountResponse {
    /** BPMN element name (falls back to element ID if name is empty) */
    elementName: string;
    /** BPMN element type (e.g. ServiceTask, ReceiveTask, IntermediateCatchEvent) */
    elementType: string;
    /** The unique process key this element belongs to */
    processKey: string;
    /** Number of failed executions of this element in the given time range */
    failedCount: number;
}
/**
 * Time bucketing granularity for insights time-series queries.
 *
 * Controls how data points are grouped on the time axis.
 */
declare enum TimeInterval {
    /** Group data points by hour */
    Hour = "HOUR",
    /** Group data points by day */
    Day = "DAY",
    /** Group data points by week */
    Week = "WEEK"
}
/**
 * Options for insights time-series queries.
 */
interface TimelineOptions {
    /**
     * How to group data points on the time axis.
     * @default TimeInterval.Day
     */
    groupBy?: TimeInterval;
}
/**
 * Final instance statuses returned by the instance status timeline endpoint.
 *
 * Only includes statuses where the instance has finished execution — Completed, Faulted, or Cancelled.
 * Active statuses like Running or Paused are not included.
 */
declare enum InstanceFinalStatus {
    /** Instance completed successfully */
    Completed = "Completed",
    /** Instance encountered an error */
    Faulted = "Faulted",
    /** Instance was cancelled */
    Cancelled = "Cancelled"
}
/**
 * Instance count for a process with a given status
 * within a specific time bucket.
 */
interface InstanceStatusTimelineResponse {
    /** Start of the time bucket in local timezone (e.g. `"5/8/2026 12:00:00 AM"`) */
    startTime: string;
    /** Instance status */
    status: InstanceFinalStatus;
    /** Number of instances with this status in the time bucket */
    count: number;
}
/**
 * Response for the top duration Insights endpoint
 */
interface GetTopDurationResponse extends GetTopBaseResponse {
    /** Total execution duration in milliseconds */
    duration: number;
}
/**
 * Element count by status for a BPMN element within a process or case
 */
interface ElementStats {
    /** BPMN element identifier */
    elementId: string;
    /** Number of successful executions */
    successCount: number;
    /** Number of failed executions */
    failCount: number;
    /** Number of terminated executions */
    terminatedCount: number;
    /** Number of paused executions */
    pausedCount: number;
    /** Number of in-progress executions */
    inProgressCount: number;
    /** Minimum duration in milliseconds */
    minDurationMs: number;
    /** Maximum duration in milliseconds */
    maxDurationMs: number;
    /** Average duration in milliseconds */
    avgDurationMs: number;
    /** 50th percentile (median) duration in milliseconds */
    p50DurationMs: number;
    /** 95th percentile duration in milliseconds */
    p95DurationMs: number;
    /** 99th percentile duration in milliseconds */
    p99DurationMs: number;
}

/**
 * Simplified universal pagination cursor
 * Used to fetch next/previous pages
 */
interface PaginationCursor {
    /** Opaque string containing all information needed to fetch next page */
    value: string;
}
/**
 * Discriminated union for pagination methods - ensures cursor and jumpToPage are mutually exclusive
 */
type PaginationMethodUnion = {
    cursor?: PaginationCursor;
    jumpToPage?: never;
} | {
    cursor?: never;
    jumpToPage?: number;
} | {
    cursor?: never;
    jumpToPage?: never;
};
/**
 * Pagination options. Users cannot specify both cursor and jumpToPage.
 */
type PaginationOptions = {
    /** Size of the page to fetch (items per page) */
    pageSize?: number;
} & PaginationMethodUnion;
/**
 * Paginated response containing items and navigation information
 */
interface PaginatedResponse<T> {
    /** The items in the current page */
    items: T[];
    /** Total count of items across all pages (if available) */
    totalCount?: number;
    /** Whether more pages are available */
    hasNextPage: boolean;
    /** Cursor to fetch the next page (if available) */
    nextCursor?: PaginationCursor;
    /** Cursor to fetch the previous page (if available) */
    previousCursor?: PaginationCursor;
    /** Current page number (1-based, if available) */
    currentPage?: number;
    /** Total number of pages (if available) */
    totalPages?: number;
    /** Whether this pagination type supports jumping to arbitrary pages */
    supportsPageJump: boolean;
}
/**
 * Response for non-paginated calls that includes both data and total count
 */
interface NonPaginatedResponse<T> {
    items: T[];
    totalCount?: number;
}
/**
 * Helper type for defining paginated method overloads
 * Creates a union type of all ways pagination can be triggered
 */
type HasPaginationOptions<T> = (T & {
    pageSize: number;
}) | (T & {
    cursor: PaginationCursor;
}) | (T & {
    jumpToPage: number;
});

/**
 * Standardized result interface for all operation methods (pause, cancel, complete, update, upload, etc.)
 * Success responses include data from the request context or API response
 */
interface OperationResponse<TData> {
    /**
     * Whether the operation was successful
     */
    success: boolean;
    /**
     * Response data (can contain error details in case of failure)
     */
    data: TData;
}
interface BaseOptions {
    expand?: string;
    select?: string;
}
/**
 * Common request options interface used across services for querying data
 */
interface RequestOptions extends BaseOptions {
    filter?: string;
    orderby?: string;
}

/**
 * Maestro Cases Types
 * Types and interfaces for Maestro case management
 */

/**
 * Case information with instance statistics
 */
interface CaseGetAllResponse {
    /** Unique key identifying the case process */
    processKey: string;
    /** Package identifier */
    packageId: string;
    /** Case name */
    name: string;
    /** Folder key of the folder where case process is located */
    folderKey: string;
    /** Name of the folder where case process is located */
    folderName: string;
    /** Available package versions */
    packageVersions: string[];
    /** Total number of versions */
    versionCount: number;
    /** Case instance count - pending */
    pendingCount: number;
    /** Case instance count - running */
    runningCount: number;
    /** Case instance count - completed */
    completedCount: number;
    /** Case instance count - paused */
    pausedCount: number;
    /** Case instance count - cancelled */
    cancelledCount: number;
    /** Case instance count - faulted */
    faultedCount: number;
    /** Case instance count - retrying */
    retryingCount: number;
    /** Case instance count - resuming */
    resumingCount: number;
    /** Case instance count - pausing */
    pausingCount: number;
    /** Case instance count - canceling */
    cancelingCount: number;
}
/**
 * Response for a single entry in top cases by run count
 */
interface CaseGetTopRunCountResponse extends GetTopRunCountResponse {
    /** Human-readable case name */
    name: string;
}
/**
 * Response for a single entry in top cases by failure count
 */
interface CaseGetTopFaultedCountResponse extends GetTopFaultedCountResponse {
    /** Human-readable case name */
    name: string;
}
/**
 * Response for a single entry in top cases by duration
 */
interface CaseGetTopDurationResponse extends GetTopDurationResponse {
    /** Human-readable case name */
    name: string;
}

/**
 * Maestro Cases Models
 * Model classes for Maestro cases
 */

/**
 * Service for managing UiPath Maestro Cases
 *
 * UiPath Maestro Case Management describes solutions that help manage and automate the full flow of complex E2E scenarios.
 *
 * ### Usage
 *
 * Prerequisites: Initialize the SDK first - see [Getting Started](/uipath-typescript/getting-started/#import-initialize)
 *
 * ```typescript
 * import { Cases } from '@uipath/uipath-typescript/cases';
 *
 * const cases = new Cases(sdk);
 * const allCases = await cases.getAll();
 * ```
 */
interface CasesServiceModel {
    /**
     * @returns Promise resolving to an array of {@link CaseGetAllWithMethodsResponse}
     * @example
     * ```typescript
     * // Get all case management processes
     * const allCases = await cases.getAll();
     *
     * // Access case information
     * for (const caseProcess of allCases) {
     *   console.log(`Case Process: ${caseProcess.processKey}`);
     *   console.log(`Running instances: ${caseProcess.runningCount}`);
     *   console.log(`Completed instances: ${caseProcess.completedCount}`);
     * }
     * ```
     */
    getAll(): Promise<CaseGetAllWithMethodsResponse[]>;
    /**
     * Get the top 5 case processes ranked by run count within a time range.
     *
     * Returns an array of up to 5 case processes sorted by how many times they were executed,
     * useful for identifying the most active case processes in a given period.
     *
     * @param startTime - Start of the time range to query
     * @param endTime - End of the time range to query
     * @param options - Optional filters (packageId, processKey, version)
     * @returns Promise resolving to an array of {@link CaseGetTopRunCountResponse}
     * @example
     * ```typescript
     * import { Cases } from '@uipath/uipath-typescript/cases';
     *
     * const cases = new Cases(sdk);
     *
     * // Get top case processes by run count for the last 7 days
     * const topProcesses = await cases.getTopRunCount(
     *   new Date(Date.now() - 7 * 24 * 60 * 60 * 1000),
     *   new Date()
     * );
     *
     * for (const process of topProcesses) {
     *   console.log(`${process.packageId}: ${process.runCount} runs`);
     * }
     * ```
     *
     * @example
     * ```typescript
     * // Get top case processes by run count for a specific package
     * const filtered = await cases.getTopRunCount(
     *   new Date(Date.now() - 7 * 24 * 60 * 60 * 1000),
     *   new Date(),
     *   { packageId: '<packageId>' }
     * );
     * ```
     */
    getTopRunCount(startTime: Date, endTime: Date, options?: TopQueryOptions): Promise<CaseGetTopRunCountResponse[]>;
    /**
     * Get the top 10 case processes ranked by failure count within a time range.
     *
     * Returns an array of up to 10 case processes sorted by how many instances faulted,
     * useful for identifying the most error-prone case processes in a given period.
     *
     * @param startTime - Start of the time range to query
     * @param endTime - End of the time range to query
     * @param options - Optional filters (packageId, processKey, version)
     * @returns Promise resolving to an array of {@link CaseGetTopFaultedCountResponse}
     * @example
     * ```typescript
     * import { Cases } from '@uipath/uipath-typescript/cases';
     *
     * const cases = new Cases(sdk);
     *
     * // Get top case processes by faulted count for the last 7 days
     * const topFailing = await cases.getTopFaultedCount(
     *   new Date(Date.now() - 7 * 24 * 60 * 60 * 1000),
     *   new Date()
     * );
     *
     * for (const process of topFailing) {
     *   console.log(`${process.packageId}: ${process.faultedCount} failures`);
     * }
     * ```
     *
     * @example
     * ```typescript
     * // Get top case processes by faulted count for a specific package
     * const filtered = await cases.getTopFaultedCount(
     *   new Date(Date.now() - 7 * 24 * 60 * 60 * 1000),
     *   new Date(),
     *   { packageId: '<packageId>' }
     * );
     * ```
     */
    getTopFaultedCount(startTime: Date, endTime: Date, options?: TopQueryOptions): Promise<CaseGetTopFaultedCountResponse[]>;
    /**
     * Get the top 10 BPMN elements ranked by failure count within a time range.
     *
     * Returns an array of up to 10 elements sorted by how many times they failed,
     * useful for identifying the most error-prone activities in case processes.
     *
     * @param startTime - Start of the time range to query
     * @param endTime - End of the time range to query
     * @param options - Optional filters (packageId, processKey, version)
     * @returns Promise resolving to an array of {@link ElementGetTopFailedCountResponse}
     * @example
     * ```typescript
     * import { Cases } from '@uipath/uipath-typescript/cases';
     *
     * const cases = new Cases(sdk);
     *
     * // Get top failing elements for the last 7 days
     * const topFailing = await cases.getTopElementFailedCount(
     *   new Date(Date.now() - 7 * 24 * 60 * 60 * 1000),
     *   new Date()
     * );
     *
     * for (const element of topFailing) {
     *   console.log(`${element.elementName} (${element.elementType}): ${element.failedCount} failures`);
     * }
     * ```
     *
     * @example
     * ```typescript
     * // Get top failing elements for a specific process
     * const filtered = await cases.getTopElementFailedCount(
     *   new Date(Date.now() - 7 * 24 * 60 * 60 * 1000),
     *   new Date(),
     *   { processKey: '<processKey>' }
     * );
     * ```
     */
    getTopElementFailedCount(startTime: Date, endTime: Date, options?: TopQueryOptions): Promise<ElementGetTopFailedCountResponse[]>;
    /**
     * Get all instances status counts aggregated by date for case management processes.
     *
     * Returns time-grouped counts of case instances grouped by status (Completed, Faulted, Cancelled),
     * useful for rendering time-series charts. Use `groupBy` to control the time bucket size
     * (hour, day, or week) — defaults to day if not provided.
     *
     * @param startTime - Start of the time range to query
     * @param endTime - End of the time range to query
     * @param options - Optional settings for time bucketing granularity
     * @returns Promise resolving to an array of {@link InstanceStatusTimelineResponse}
     *
     * @example
     * ```typescript
     * // Get daily instance status for the last 7 days
     * const now = new Date();
     * const sevenDaysAgo = new Date(Date.now() - 7 * 24 * 60 * 60 * 1000);
     * const statuses = await cases.getInstanceStatusTimeline(sevenDaysAgo, now);
     *
     * for (const entry of statuses) {
     *   console.log(`${entry.startTime} — ${entry.status}: ${entry.count}`);
     * }
     * ```
     *
     * @example
     * ```typescript
     * import { TimeInterval } from '@uipath/uipath-typescript/cases';
     *
     * // Get weekly breakdown
     * const statuses = await cases.getInstanceStatusTimeline(startTime, endTime, {
     *   groupBy: TimeInterval.Week,
     * });
     * ```
     *
     * @example
     * ```typescript
     * // Get all-time data (from Unix epoch to now)
     * const allTime = await cases.getInstanceStatusTimeline(new Date(0), new Date());
     * ```
     */
    getInstanceStatusTimeline(startTime: Date, endTime: Date, options?: TimelineOptions): Promise<InstanceStatusTimelineResponse[]>;
    /**
     * Get the top 5 case processes ranked by total duration within a time range.
     *
     * Returns an array of up to 5 case processes sorted by their total execution time,
     * useful for identifying the longest-running case processes in a given period.
     *
     * @param startTime - Start of the time range to query
     * @param endTime - End of the time range to query
     * @param options - Optional filters (packageId, processKey, version)
     * @returns Promise resolving to an array of {@link CaseGetTopDurationResponse}
     * @example
     * ```typescript
     * import { Cases } from '@uipath/uipath-typescript/cases';
     *
     * const cases = new Cases(sdk);
     *
     * // Get top case processes by duration for the last 7 days
     * const topProcesses = await cases.getTopExecutionDuration(
     *   new Date(Date.now() - 7 * 24 * 60 * 60 * 1000),
     *   new Date()
     * );
     *
     * for (const process of topProcesses) {
     *   console.log(`${process.packageId}: ${process.duration}ms total`);
     * }
     * ```
     *
     * @example
     * ```typescript
     * // Get top case processes by duration for a specific package
     * const filtered = await cases.getTopExecutionDuration(
     *   new Date(Date.now() - 7 * 24 * 60 * 60 * 1000),
     *   new Date(),
     *   { packageId: '<packageId>' }
     * );
     * ```
     */
    getTopExecutionDuration(startTime: Date, endTime: Date, options?: TopQueryOptions): Promise<CaseGetTopDurationResponse[]>;
    /**
     * Get element stats for case instances
     *
     * Returns per-element execution counts (success, fail, terminated, paused, in-progress) and
     * duration percentile metrics (min, max, avg, p50, p95, p99) for BPMN elements within a case.
     *
     * @param processKey - Process key to filter by
     * @param packageId - Package identifier
     * @param startTime - Start of the time range to query
     * @param endTime - End of the time range to query
     * @param packageVersion - Package version to filter by
     * @returns Promise resolving to an array of {@link ElementStats}
     * @example
     * ```typescript
     * // Get element metrics for a case
     * const elements = await cases.getElementStats(
     *   '<processKey>',
     *   '<packageId>',
     *   new Date('2026-04-01'),
     *   new Date(),
     *   '1.0.1'
     * );
     *
     * // Find elements with failures
     * const failedElements = elements.filter(e => e.failCount > 0);
     * for (const element of failedElements) {
     *   console.log(`Failed element: ${element.elementId}, failures: ${element.failCount}`);
     * }
     * ```
     */
    getElementStats(processKey: string, packageId: string, startTime: Date, endTime: Date, packageVersion: string): Promise<ElementStats[]>;
}
interface CaseMethods {
    /**
     * Get element stats for this case
     *
     * @param startTime - Start of the time range to query
     * @param endTime - End of the time range to query
     * @param packageVersion - Package version to filter by
     * @returns Promise resolving to an array of {@link ElementStats}
     */
    getElementStats(startTime: Date, endTime: Date, packageVersion: string): Promise<ElementStats[]>;
}
type CaseGetAllWithMethodsResponse = CaseGetAllResponse & CaseMethods;
/**
 * Creates an actionable case by combining API case data with operational methods.
 *
 * @param caseData - The case data from API
 * @param service - The cases service instance
 * @returns A case object with added methods
 */
declare function createCaseWithMethods(caseData: CaseGetAllResponse, service: CasesServiceModel): CaseGetAllWithMethodsResponse;

